#!/usr/bin/env Rscript
# T038: Validate log file warning ratio is <= 5% of total processed records (SC-005)
#
# This script scans log files generated by the pipeline, counts total processed records
# and warning messages, and verifies the warning ratio is <= 5%.
#
# Usage: Rscript src/code/validate_log_ratio.R
#
# Output: Prints validation result to stdout and writes a summary to results/validation_log_ratio.csv

# Load dependencies
if (!require("here", quietly = TRUE)) {
  stop("Package 'here' is required. Install it via install.packages('here').")
}
if (!require("dplyr", quietly = TRUE)) {
  stop("Package 'dplyr' is required. Install it via install.packages('dplyr').")
}
if (!require("lubridate", quietly = TRUE)) {
  stop("Package 'lubridate' is required. Install it via install.packages('lubridate').")
}

# Configuration
LOG_DIR <- here("logs")
RESULTS_DIR <- here("results")
OUTPUT_FILE <- file.path(RESULTS_DIR, "validation_log_ratio.csv")
MAX_WARNING_RATIO <- 0.05

# Ensure results directory exists
if (!dir.exists(RESULTS_DIR)) {
  dir.create(RESULTS_DIR, recursive = TRUE)
}

# Function to parse log files
parse_log_file <- function(file_path) {
  if (!file.exists(file_path)) {
    return(NULL)
  }

  lines <- readLines(file_path, warn = FALSE)

  # Count total processed records (look for patterns like "Processed N records" or "Total records: N")
  # Adjust regex based on actual log format from utils.R
  total_records_pattern <- "(?i)(processed|total|count)[^0-9]*([0-9]+)[^0-9]*(record|entry|row)"
  total_matches <- grepl(total_records_pattern, lines, perl = TRUE)
  total_records <- sum(as.numeric(sub(total_records_pattern, "\\2", lines[total_matches], perl = TRUE)), na.rm = TRUE)

  # Count warning messages (look for "WARNING" or "WARN" in the line)
  warning_pattern <- "(?i)(warning|warn)"
  warning_count <- sum(grepl(warning_pattern, lines, perl = TRUE))

  # If no records found, try to infer from log entries (e.g., count lines with timestamps)
  if (total_records == 0) {
    timestamp_pattern <- "^\\d{4}-\\d{2}-\\d{2}"
    total_records <- sum(grepl(timestamp_pattern, lines))
  }

  list(
    file = basename(file_path),
    total_records = total_records,
    warning_count = warning_count
  )
}

# Main execution
main <- function() {
  cat("=== T038: Validating Log File Warning Ratio (SC-005) ===\n")

  if (!dir.exists(LOG_DIR)) {
    stop("Log directory not found: ", LOG_DIR, ". Please ensure logs have been generated.")
  }

  log_files <- list.files(LOG_DIR, pattern = "\\.log$", full.names = TRUE)

  if (length(log_files) == 0) {
    stop("No log files found in ", LOG_DIR, ". Please ensure the pipeline has been run to generate logs.")
  }

  cat("Found", length(log_files), "log file(s) to analyze.\n")

  results <- lapply(log_files, parse_log_file)
  results_df <- do.call(rbind, lapply(results, function(x) {
    data.frame(
      file = x$file,
      total_records = x$total_records,
      warning_count = x$warning_count,
      stringsAsFactors = FALSE
    )
  }))

  # Calculate totals
  total_records_all <- sum(results_df$total_records, na.rm = TRUE)
  total_warnings_all <- sum(results_df$warning_count, na.rm = TRUE)

  if (total_records_all == 0) {
    stop("No processed records found in log files. Cannot calculate warning ratio.")
  }

  warning_ratio <- total_warnings_all / total_records_all

  cat(sprintf("Total processed records: %d\n", total_records_all))
  cat(sprintf("Total warning messages: %d\n", total_warnings_all))
  cat(sprintf("Warning ratio: %.4f (%.2f%%)\n", warning_ratio, warning_ratio * 100))
  cat(sprintf("Threshold (SC-005): %.2f%%\n", MAX_WARNING_RATIO * 100))

  # Validation result
  passed <- warning_ratio <= MAX_WARNING_RATIO

  if (passed) {
    cat("✓ VALIDATION PASSED: Warning ratio is within acceptable limits.\n")
  } else {
    cat("✗ VALIDATION FAILED: Warning ratio exceeds 5% threshold.\n")
  }

  # Write summary to CSV
  summary_row <- data.frame(
    metric = "log_warning_ratio",
    total_records = total_records_all,
    total_warnings = total_warnings_all,
    warning_ratio = warning_ratio,
    threshold = MAX_WARNING_RATIO,
    passed = passed,
    timestamp = format(Sys.time(), "%Y-%m-%d %H:%M:%S"),
    stringsAsFactors = FALSE
  )

  write.csv(summary_row, OUTPUT_FILE, row.names = FALSE)
  cat(sprintf("Summary written to: %s\n", OUTPUT_FILE))

  # Exit with appropriate code
  if (!passed) {
    quit(status = 1)
  }
}

# Run main
main()
